cat /home/archon/.claude-guoxiong/projects/-home-archon-FormalizationProjects-Algebraic-Jacobian-Challenge/be20c11f-c7a6-489b-9be2-ed84665435fd/tool-results/bcdqlyyxu.txt | python3 -c "
import json, sys
for line in sys.stdin:
    line=line.strip()
    if not line: continue
    try:
        o=json.loads(line)
    except: 
        continue
    t=o.get('type')
    if t=='summary': 
        print('SUMMARY:', json.dumps(o)); continue
    if t=='file_read': continue
    if t=='code_change':
        print('---EDIT line', o.get('log_line'), 'file:', (o.get('file') or '').split('/')[-1])
        print('OLD:', repr((o.get('old_text') or '')[:400]))
        print('NEW:', repr((o.get('new_text') or '')[:400]))
    elif t=='diagnostics':
        ec=o.get('error_count'); 
        if ec and ec>0:
            print('DIAG', (o.get('file') or '').split('/')[-1], 'errors=',ec)
            for e in (o.get('errors') or [])[:5]:
                print('   ERR:', json.dumps(e)[:300])
    elif t=='goal_state':
        print('GOAL line', o.get('log_line'), ':', json.dumps(o)[:400])
    else:
        print('OTHER', t, json.dumps(o)[:200])
"

